  const estabaModificando =
    appsmith.store.modoSP === "MODIFICAR";

  return Promise.all([

    storeValue("detalleSP", []),
    storeValue("idProyectoSP", null),
    storeValue("idSuplidorSP", null),
    storeValue("idMonedaSP", null),

    storeValue("modoSP", null),
    storeValue("idSPModificar", null),
    storeValue("encabezadoSP", null),

    resetWidget("inpID_SP"),
    resetWidget("inpNumeroSP"),

    resetWidget("inpConceptoSP"),

    resetWidget("inpRetIbisSP"),
    resetWidget("inpRetDGIISP"),
    resetWidget("inpRetGarantiaSP"),
    resetWidget("inpRetTSSSP"),

    resetWidget("selOtraMonedaSP"),
    resetWidget("selOtraMonedaCodigoSP"),
    resetWidget("inpTasaOtraMoneda"),

    resetWidget("inpFCparaSPlinea"),
    resetWidget("inpValorSolicitadoSP")

  ]).then(() => {

    showAlert(
      "Formulario limpiado",
      "success"
